cv_addCurve.example:
cv_createFromScript c1 {0 1} {1 2}
cv_createFromScript c2 {0 1} {3 4}
cv_addCurve c1 c2
puts "y: [cv_getValsY c1]"

cv_angularMap.example:
cv_createFromScript a {0 1 2 90 91 92} {1 2 3 4 5 6}
cv_angularMap a
puts [cv_getVals a]

cv_monotonicX.example:
cv_createFromScript iv {0 1 2 0 2 4} {1 2 3 4 5 6}
cv_monotonicX iv
puts "values: [cv_getVals iv]"

cv_sort.example:
cv_createFromScript c {1 2 0.0001 3 0} {2 3 -1 4 1}
cv_sort c 3
puts "[cv_getVals c]"

cv_round.example:
cv_createFromScript c {1.01 5.05} {9.09 7.07}
cv_round c 1 1
puts "[cv_getVals c]"

gr_resetAxis.example:
gr_axis x {voltage [V]}
gr_axis y {current [A]} {} log
gr_resetAxis

ldiff.example:
set l1 {1 2 3 4}
set l2 {1 2 5}
puts "[ldiff $l1 $l2]"
# => 3 4
puts "[ldiff $l1 $l2 1]"
# => 3 4 5
